const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = "LAYOUT_16x9";
pres.author = "Michael Forrester";
pres.title = "Agentic DevOps: The Playbook for Working Engineers";

// ── Theme constants ──
const BG = "1E2761";
const BG_LIGHT = "253272";
const ICE = "CADCFC";
const WHITE = "FFFFFF";
const MUTED = "8B9DC3";
const DARK_CARD = "162050";
const ACCENT_GREEN = "4ADE80";
const ACCENT_RED = "F87171";
const ACCENT_AMBER = "FBBF24";
const FONT = "Calibri";
const FONT_BOLD = "Calibri";

// ── Helpers ──
function makeShadow() {
  return { type: "outer", blur: 4, offset: 2, angle: 135, color: "000000", opacity: 0.25 };
}

function addCard(slide, x, y, w, h, fillColor) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h,
    fill: { color: fillColor || DARK_CARD },
    shadow: makeShadow(),
  });
}

function sectionNumber(slide, num) {
  slide.addText(String(num), {
    x: 0.6, y: 1.4, w: 1.2, h: 1.2,
    fontSize: 60, fontFace: FONT, color: ICE, bold: true, align: "center", valign: "middle",
  });
}

function slideFooter(slide, text) {
  slide.addText(text || "KodeKloud | April 2026", {
    x: 0.5, y: 5.15, w: 9, h: 0.35,
    fontSize: 9, fontFace: FONT, color: MUTED, align: "left",
  });
}

// ════════════════════════════════════════════════════════════
// SLIDE 1 — Pre-session hold screen
// ════════════════════════════════════════════════════════════
let s1 = pres.addSlide();
s1.background = { color: BG };
s1.addText("AGENTIC DEVOPS", {
  x: 0.8, y: 1.5, w: 8.4, h: 1.0,
  fontSize: 44, fontFace: FONT, color: WHITE, bold: true, align: "center", charSpacing: 4,
});
s1.addText("The Playbook for Working Engineers", {
  x: 0.8, y: 2.5, w: 8.4, h: 0.6,
  fontSize: 20, fontFace: FONT, color: ICE, align: "center",
});
s1.addText("Live Session  |  April 2026", {
  x: 0.8, y: 3.4, w: 8.4, h: 0.5,
  fontSize: 14, fontFace: FONT, color: MUTED, align: "center",
});
s1.addShape(pres.shapes.LINE, {
  x: 3.5, y: 3.2, w: 3, h: 0,
  line: { color: ICE, width: 1 },
});
s1.addNotes("PRE-SESSION — Title Hold Screen\n\nHave your outline open in a second window. Know your five section transitions cold.\n\nWater nearby. Chat window open. Check: mic levels, camera framing, slide advancer working, backup slides loaded.\n\nPlay holding music or ambient screen while people join.");

// ════════════════════════════════════════════════════════════
// SLIDE 2 — Title with presenter
// ════════════════════════════════════════════════════════════
let s2 = pres.addSlide();
s2.background = { color: BG };
s2.addText("AGENTIC DEVOPS", {
  x: 0.8, y: 1.2, w: 8.4, h: 0.9,
  fontSize: 40, fontFace: FONT, color: WHITE, bold: true, align: "center", charSpacing: 4,
});
s2.addText("The Playbook for Working Engineers", {
  x: 0.8, y: 2.1, w: 8.4, h: 0.5,
  fontSize: 18, fontFace: FONT, color: ICE, align: "center",
});
s2.addShape(pres.shapes.LINE, {
  x: 3.5, y: 2.8, w: 3, h: 0,
  line: { color: ICE, width: 1 },
});
s2.addText("Michael Forrester", {
  x: 0.8, y: 3.1, w: 8.4, h: 0.5,
  fontSize: 18, fontFace: FONT, color: WHITE, bold: true, align: "center",
});
s2.addText("Senior Principal Trainer & DevOps Advocate", {
  x: 0.8, y: 3.55, w: 8.4, h: 0.4,
  fontSize: 13, fontFace: FONT, color: ICE, align: "center",
});
s2.addText("KodeKloud  |  April 2026", {
  x: 0.8, y: 3.95, w: 8.4, h: 0.4,
  fontSize: 12, fontFace: FONT, color: MUTED, align: "center",
});
s2.addNotes("Welcome everyone, thanks for joining today. I'm Michael Forrester, Senior Principal Trainer and DevOps Advocate at KodeKloud.\n\nToday we're going to cut through the noise on what Agentic DevOps actually means for working engineers. Not vendor pitches. Not 2030 predictions. What's confirmed in production right now, and what you can start doing Monday morning.\n\nLet's get into it.");

// ════════════════════════════════════════════════════════════
// SLIDE 3 — ONE WEEK. DECEMBER 2025. (Updated: AWS + Azure now GA)
// ════════════════════════════════════════════════════════════
let s3 = pres.addSlide();
s3.background = { color: BG };
s3.addText("DECEMBER 2025 — ONE WEEK.", {
  x: 0.6, y: 0.3, w: 8.8, h: 0.6,
  fontSize: 24, fontFace: FONT, color: WHITE, bold: true, align: "center",
});
s3.addText("All three major cloud platforms shipped autonomous DevOps agents in the same week.", {
  x: 1.0, y: 0.85, w: 8.0, h: 0.45,
  fontSize: 13, fontFace: FONT, color: ICE, align: "center",
});

// Three cloud cards
const clouds = [
  { name: "AWS", product: "DevOps Agent\n+ Security Agent", status: "GA", statusDetail: "March 31, 2026", desc: "Autonomous incident\nresolution & pen testing", color: ACCENT_GREEN },
  { name: "MICROSOFT", product: "Azure SRE Agent", status: "GA", statusDetail: "March 10, 2026", desc: "1,300+ agents deployed\n35K+ incidents mitigated", color: ACCENT_GREEN },
  { name: "GOOGLE", product: "Cloud SRE Agent", status: "Preview", statusDetail: "ADK/Gemini CLI toolkit", desc: "Autonomous operations\nof DevOps workflows", color: ACCENT_AMBER },
];

clouds.forEach((c, i) => {
  const cx = 0.6 + i * 3.1;
  addCard(s3, cx, 1.55, 2.9, 2.75, DARK_CARD);
  s3.addText(c.name, {
    x: cx, y: 1.65, w: 2.9, h: 0.4,
    fontSize: 16, fontFace: FONT, color: WHITE, bold: true, align: "center",
  });
  s3.addText(c.product, {
    x: cx + 0.15, y: 2.05, w: 2.6, h: 0.55,
    fontSize: 11, fontFace: FONT, color: ICE, align: "center", valign: "top",
  });
  // Status badge
  s3.addShape(pres.shapes.ROUNDED_RECTANGLE, {
    x: cx + 0.7, y: 2.65, w: 1.5, h: 0.35,
    fill: { color: c.color, transparency: 20 },
    rectRadius: 0.05,
  });
  s3.addText(c.status, {
    x: cx + 0.7, y: 2.65, w: 1.5, h: 0.35,
    fontSize: 11, fontFace: FONT, color: c.color, bold: true, align: "center", valign: "middle",
  });
  s3.addText(c.statusDetail, {
    x: cx + 0.15, y: 3.05, w: 2.6, h: 0.3,
    fontSize: 9, fontFace: FONT, color: MUTED, align: "center",
  });
  s3.addText(c.desc, {
    x: cx + 0.15, y: 3.35, w: 2.6, h: 0.7,
    fontSize: 10, fontFace: FONT, color: "A0B0D0", align: "center",
  });
});

s3.addText([
  { text: "That's not a coincidence. That's a race. ", options: { bold: true, color: WHITE } },
  { text: "Agentic operations is the next platform layer every major cloud is competing on.", options: { color: ICE } },
], {
  x: 0.6, y: 4.55, w: 8.8, h: 0.6,
  fontSize: 13, fontFace: FONT, align: "center",
});
slideFooter(s3);
s3.addNotes("UPDATED since the original deck: AWS and Microsoft have both moved their agents to General Availability in the last five weeks.\n\nAWS DevOps Agent went GA March 31 — autonomous incident resolution across AWS, Azure, and on-prem. Named customers: United Airlines, WGU, T-Mobile. WGU reported 77% reduction in resolution time.\n\nAzure SRE Agent went GA March 10. Microsoft runs 1,300+ agents internally, mitigated 35,000+ incidents, saving 20,000+ engineering hours per month.\n\nGoogle hasn't shipped a specific GA agent product — they're taking a toolkit approach with Gemini CLI and ADK.\n\nThe point stands, but it's even stronger now: this went from three simultaneous previews to two GA products inside of 90 days. This isn't experimental anymore.");

// ════════════════════════════════════════════════════════════
// SLIDE 4 — WHAT'S ACTUALLY HAPPENING RIGHT NOW (Stats updated)
// ════════════════════════════════════════════════════════════
let s4 = pres.addSlide();
s4.background = { color: BG };
s4.addText("WHAT'S ACTUALLY HAPPENING RIGHT NOW", {
  x: 0.6, y: 0.3, w: 8.8, h: 0.55,
  fontSize: 22, fontFace: FONT, color: WHITE, bold: true, align: "center",
});

const stats = [
  { big: "4.6x", desc: "longer AI-generated\nPRs wait for review\nvs. human PRs" },
  { big: "1.2M/mo", desc: "PRs created by GitHub\nCopilot coding agent\n(early 2026)" },
  { big: "46%", desc: "of active Copilot users'\ncode is AI-generated\n(up to 61% for Java)" },
  { big: "2,000+", desc: "Production envs where\nDatadog AI SRE Agent\nis running" },
  { big: "90%", desc: "of Fortune 100\ncompanies now using\nGitHub Copilot" },
];

// Top row: 3 stats
stats.slice(0, 3).forEach((st, i) => {
  const sx = 0.5 + i * 3.15;
  addCard(s4, sx, 1.0, 2.95, 1.7, DARK_CARD);
  s4.addText(st.big, {
    x: sx, y: 1.05, w: 2.95, h: 0.65,
    fontSize: 32, fontFace: FONT, color: ICE, bold: true, align: "center", valign: "middle",
  });
  s4.addText(st.desc, {
    x: sx + 0.15, y: 1.7, w: 2.65, h: 0.85,
    fontSize: 10, fontFace: FONT, color: MUTED, align: "center", valign: "top",
  });
});

// Bottom row: 2 stats centered
stats.slice(3).forEach((st, i) => {
  const sx = 1.9 + i * 3.4;
  addCard(s4, sx, 2.95, 2.95, 1.7, DARK_CARD);
  s4.addText(st.big, {
    x: sx, y: 3.0, w: 2.95, h: 0.65,
    fontSize: 32, fontFace: FONT, color: ICE, bold: true, align: "center", valign: "middle",
  });
  s4.addText(st.desc, {
    x: sx + 0.15, y: 3.65, w: 2.65, h: 0.85,
    fontSize: 10, fontFace: FONT, color: MUTED, align: "center", valign: "top",
  });
});

slideFooter(s4);
s4.addNotes("Let's ground this in data, not vibes.\n\n4.6x: AI-generated PRs wait 4.6 times longer for review than human-written ones. That's from Opsera's 2026 AI Coding Impact Benchmark — 250,000+ developers, 60+ enterprises.\n\n1.2 million PRs per month: That's what Copilot's coding agent is creating autonomously as of early 2026. Assign an issue, come back to a draft PR.\n\n46%: Nearly half the code written by Copilot users is AI-generated. Java devs are at 61%.\n\n2,000+ production environments running Datadog's Bits AI SRE Agent since GA in December.\n\n90% of the Fortune 100 are using Copilot.\n\nCode creation has been solved. The downstream pipeline — review, deployment, monitoring, incident response — that's where the bottleneck moved.");

// ════════════════════════════════════════════════════════════
// SLIDE 5 — THIS WEBINAR: What this is / isn't
// ════════════════════════════════════════════════════════════
let s5 = pres.addSlide();
s5.background = { color: BG };
s5.addText("THIS WEBINAR", {
  x: 0.6, y: 0.3, w: 8.8, h: 0.55,
  fontSize: 24, fontFace: FONT, color: WHITE, bold: true, align: "center",
});

// Two columns
const colL = 0.6, colR = 5.2, colW = 4.3;

addCard(s5, colL, 1.0, colW, 3.8, DARK_CARD);
s5.addText("WHAT THIS IS", {
  x: colL, y: 1.1, w: colW, h: 0.4,
  fontSize: 14, fontFace: FONT, color: ACCENT_GREEN, bold: true, align: "center",
});
const isItems = [
  "A decision framework for working engineers",
  "Grounded in what's confirmed in production right now",
  "A 90-day plan you can start Monday",
];
s5.addText(isItems.map((t, i) => ({
  text: `✔  ${t}`,
  options: { breakLine: i < isItems.length - 1, color: WHITE, fontSize: 12 },
})), { x: colL + 0.3, y: 1.6, w: colW - 0.6, h: 2.8, fontFace: FONT, paraSpaceAfter: 14 });

addCard(s5, colR, 1.0, colW, 3.8, DARK_CARD);
s5.addText("WHAT THIS ISN'T", {
  x: colR, y: 1.1, w: colW, h: 0.4,
  fontSize: 14, fontFace: FONT, color: ACCENT_RED, bold: true, align: "center",
});
const isntItems = [
  "A tools demo",
  "Hype about what's possible in 2030",
  "A message that your skills are becoming worthless",
];
s5.addText(isntItems.map((t, i) => ({
  text: `✕  ${t}`,
  options: { breakLine: i < isntItems.length - 1, color: WHITE, fontSize: 12 },
})), { x: colR + 0.3, y: 1.6, w: colW - 0.6, h: 2.8, fontFace: FONT, paraSpaceAfter: 14 });

slideFooter(s5);
s5.addNotes("Set expectations early. This is not a vendor demo — we're tool-neutral. Not hype — everything is sourced. Not doom — DevOps skills are the foundation agents run on.\n\nThis is a decision framework: What is Agentic DevOps, what's real, how does it affect your role, and what do you do about it in the next 90 days.");

// ════════════════════════════════════════════════════════════
// SLIDE 6 — Section 2 divider: What is Agentic DevOps
// ════════════════════════════════════════════════════════════
let s6 = pres.addSlide();
s6.background = { color: BG_LIGHT };
sectionNumber(s6, 2);
s6.addText("WHAT IS AGENTIC\nDEVOPS, ACTUALLY", {
  x: 2.0, y: 1.4, w: 7.0, h: 1.2,
  fontSize: 32, fontFace: FONT, color: WHITE, bold: true,
});
s6.addText("Cutting through the noise with a definition that sticks", {
  x: 2.0, y: 2.7, w: 7.0, h: 0.5,
  fontSize: 14, fontFace: FONT, color: ICE,
});
s6.addNotes("Transition: OK, so what does 'Agentic DevOps' actually mean? Everyone's using the term. Most people mean different things by it. Let's pin it down.");

// ════════════════════════════════════════════════════════════
// SLIDE 7 — Where the bottleneck moved (Inner/Outer loop)
// ════════════════════════════════════════════════════════════
let s7 = pres.addSlide();
s7.background = { color: BG };
s7.addText("WHERE THE BOTTLENECK MOVED", {
  x: 0.6, y: 0.3, w: 8.8, h: 0.5,
  fontSize: 22, fontFace: FONT, color: WHITE, bold: true, align: "center",
});

// Two columns: Inner Loop / Outer Loop
addCard(s7, 0.5, 0.95, 4.2, 3.2, DARK_CARD);
s7.addText("Inner Loop", {
  x: 0.5, y: 1.0, w: 4.2, h: 0.4,
  fontSize: 16, fontFace: FONT, color: ICE, bold: true, align: "center",
});
s7.addText("(Where AI Started)", {
  x: 0.5, y: 1.35, w: 4.2, h: 0.3,
  fontSize: 10, fontFace: FONT, color: MUTED, align: "center",
});
const innerItems = ["Code writing", "Code completion", "Test generation"];
s7.addText(innerItems.map((t, i) => ({
  text: t, options: { breakLine: i < innerItems.length - 1, fontSize: 12, color: WHITE },
})), { x: 0.8, y: 1.75, w: 3.6, h: 1.5, fontFace: FONT, paraSpaceAfter: 8, bullet: true });
s7.addText("AI moved here →", {
  x: 0.5, y: 3.4, w: 4.2, h: 0.35,
  fontSize: 11, fontFace: FONT, color: ACCENT_GREEN, bold: true, align: "center",
});

addCard(s7, 5.3, 0.95, 4.2, 3.2, DARK_CARD);
s7.addText("Outer Loop", {
  x: 5.3, y: 1.0, w: 4.2, h: 0.4,
  fontSize: 16, fontFace: FONT, color: ICE, bold: true, align: "center",
});
s7.addText("(Where AI is Going)", {
  x: 5.3, y: 1.35, w: 4.2, h: 0.3,
  fontSize: 10, fontFace: FONT, color: MUTED, align: "center",
});
const outerItems = ["Code review & PR approval", "CI/CD pipeline management", "Deployment orchestration", "Monitoring & alerting", "Incident response", "Runbook execution"];
s7.addText(outerItems.map((t, i) => ({
  text: t, options: { breakLine: i < outerItems.length - 1, fontSize: 11, color: WHITE },
})), { x: 5.6, y: 1.75, w: 3.6, h: 2.3, fontFace: FONT, paraSpaceAfter: 4, bullet: true });

// Bottom callout
addCard(s7, 0.5, 4.35, 9.0, 0.85, DARK_CARD);
s7.addText([
  { text: "AI-generated PRs created 48% faster ", options: { color: ACCENT_GREEN, bold: true } },
  { text: "but waited ", options: { color: WHITE } },
  { text: "4.6× longer to be reviewed ", options: { color: ACCENT_RED, bold: true } },
  { text: "and contained 15–18% more security vulnerabilities. ", options: { color: WHITE } },
  { text: "(Opsera, 2026)", options: { color: MUTED, fontSize: 9 } },
], { x: 0.8, y: 4.4, w: 8.4, h: 0.75, fontSize: 11, fontFace: FONT, align: "center", valign: "middle" });

slideFooter(s7);
s7.addNotes("This is the core problem statement.\n\nThe inner loop — code writing, completion, test generation — AI has been here for 2+ years. It's fast. PRs created 48% faster.\n\nBut the outer loop — review, CI/CD, deployment, monitoring, incident response — that's where the bottleneck moved. AI-generated PRs wait 4.6x longer for review. They contain 15–18% more security vulnerabilities.\n\nCode creation has been solved. The pipeline hasn't. That's the gap agentic DevOps is trying to close.");

// ════════════════════════════════════════════════════════════
// SLIDE 8 — What Agentic DevOps actually is (definition)
// ════════════════════════════════════════════════════════════
let s8 = pres.addSlide();
s8.background = { color: BG };
s8.addText("WHAT AGENTIC DEVOPS ACTUALLY IS", {
  x: 0.6, y: 0.3, w: 8.8, h: 0.5,
  fontSize: 22, fontFace: FONT, color: WHITE, bold: true, align: "center",
});

addCard(s8, 0.8, 1.0, 8.4, 1.5, DARK_CARD);
s8.addText([
  { text: '"Autonomous, goal-driven AI systems operating ', options: { italic: true, color: ICE, fontSize: 13 } },
  { text: "within your existing infrastructure", options: { italic: true, color: ACCENT_GREEN, bold: true, fontSize: 13 } },
  { text: ' — Kubernetes, CI/CD, observability tooling — that can plan, execute, and iterate on multi-step tasks without constant human direction."', options: { italic: true, color: ICE, fontSize: 13 } },
], { x: 1.1, y: 1.1, w: 7.8, h: 1.3, fontFace: FONT, align: "center", valign: "middle" });

s8.addText("The key phrase:", {
  x: 0.8, y: 2.8, w: 8.4, h: 0.35,
  fontSize: 12, fontFace: FONT, color: MUTED, align: "center",
});
s8.addText("WITHIN YOUR EXISTING INFRASTRUCTURE", {
  x: 0.8, y: 3.15, w: 8.4, h: 0.5,
  fontSize: 22, fontFace: FONT, color: ICE, bold: true, align: "center", charSpacing: 2,
});

addCard(s8, 1.5, 3.85, 7.0, 1.2, DARK_CARD);
s8.addText([
  { text: "Agents run on your stack — not instead of it. ", options: { color: WHITE, fontSize: 12 } },
  { text: 'Human role shifts: from "in the loop" (approving every step) to "on the loop" (monitoring outcomes, intervening only when needed).', options: { color: MUTED, fontSize: 11 } },
], { x: 1.8, y: 3.95, w: 6.4, h: 1.0, fontFace: FONT, align: "center", valign: "middle" });

slideFooter(s8);
s8.addNotes("Here's the definition we're working with today.\n\nThe key phrase is 'within your existing infrastructure.' Agents run on Kubernetes. They're embedded in CI/CD pipelines. They query your observability stack. They don't replace your stack — they operate within it.\n\nThe human role shift: from 'in the loop' — approving every action — to 'on the loop' — monitoring outcomes and intervening when needed.\n\nThis is why your existing DevOps knowledge matters. You already know the infrastructure agents operate on.");

// ════════════════════════════════════════════════════════════
// SLIDE 9 — Opportunity and Risk
// ════════════════════════════════════════════════════════════
let s9 = pres.addSlide();
s9.background = { color: BG };
s9.addText("OPPORTUNITY AND RISK — BOTH ARE REAL", {
  x: 0.6, y: 0.3, w: 8.8, h: 0.5,
  fontSize: 20, fontFace: FONT, color: WHITE, bold: true, align: "center",
});

// Left column: Opportunity
addCard(s9, 0.5, 0.95, 4.2, 3.8, DARK_CARD);
s9.addText("THE OPPORTUNITY", {
  x: 0.5, y: 1.05, w: 4.2, h: 0.35,
  fontSize: 14, fontFace: FONT, color: ACCENT_GREEN, bold: true, align: "center",
});
const oppItems = [
  "Autonomous incident triage at scale",
  "Self-healing CI/CD pipelines",
  "Infrastructure changes from natural language",
];
s9.addText(oppItems.map((t, i) => ({
  text: `✔  ${t}`,
  options: { breakLine: i < oppItems.length - 1, fontSize: 11, color: WHITE },
})), { x: 0.8, y: 1.55, w: 3.6, h: 2.0, fontFace: FONT, paraSpaceAfter: 10 });

// Right column: Risk
addCard(s9, 5.3, 0.95, 4.2, 3.8, DARK_CARD);
s9.addText("THE REAL RISK", {
  x: 5.3, y: 1.05, w: 4.2, h: 0.35,
  fontSize: 14, fontFace: FONT, color: ACCENT_RED, bold: true, align: "center",
});
const riskItems = [
  { text: "Forrester predicts a major breach from Agentic AI with insufficient governance will occur in 2026", color: WHITE },
  { text: "Snyk (Feb 2026): 13.4% of public agent skills had critical vulnerabilities; 76 confirmed malicious payloads", color: WHITE },
  { text: "2025 DORA Report: AI still negatively correlates with delivery stability", color: WHITE },
];
s9.addText(riskItems.map((t, i) => ({
  text: `✕  ${t.text}`,
  options: { breakLine: i < riskItems.length - 1, fontSize: 10, color: t.color },
})), { x: 5.6, y: 1.55, w: 3.6, h: 3.0, fontFace: FONT, paraSpaceAfter: 10 });

slideFooter(s9);
s9.addNotes("This is where we stay honest.\n\nThe opportunity is real: autonomous incident triage, self-healing pipelines, natural-language infra changes.\n\nBut the risks are equally real and sourced:\n- Forrester predicts a major breach from ungoverned agentic AI this year\n- Snyk found 13.4% of public agent skills had critical vulnerabilities. 76 confirmed malicious payloads. Treat agent skills like npm packages.\n- The 2025 DORA Report found AI negatively correlates with delivery stability\n\nRECENT EXAMPLE TO MENTION: Two weeks ago, March 30 — GitHub Copilot was caught injecting product ads into 11,000+ pull requests without developer consent. It edited PR descriptions to include Raycast promotions. GitHub killed it same day, called it 'the wrong judgement call.' That's what happens when an agent's permission scope isn't locked down. Perfect example of why boundary design matters — and we'll talk about that in Section 4.");

// ════════════════════════════════════════════════════════════
// SLIDE 10 — WHERE ARE TEAMS ACTUALLY? (Maturity Model) (Fixed title)
// ════════════════════════════════════════════════════════════
let s10 = pres.addSlide();
s10.background = { color: BG };
s10.addText("WHERE ARE TEAMS ACTUALLY?", {
  x: 0.6, y: 0.2, w: 8.8, h: 0.5,
  fontSize: 22, fontFace: FONT, color: WHITE, bold: true, align: "center",
});

const levels = [
